form:Form.form:Scripts:
		function LoadForm()
{
	if(Ctrl('EveES').GetXValue() == '1')
	{
		Ctrl('TipoClasif').SetXValue('N');
		CtrlEnabled('TipoClasif', false);	
	}
}

function SetClasif()
{	
	if(Ctrl('EveES').GetXValue() == '1')
	{
		Ctrl('TipoClasif').SetXValue('N');
		CtrlEnabled('TipoClasif', false);	
	}
	else
	{
		CtrlEnabled('TipoClasif', true);
		Ctrl('TipoClasif').SetXValue('');		
	}
}

function ValClasif(me)
{
	if(Ctrl('EveES').GetXValue() != '1' && Ctrl('TipoClasif').GetXValue() == 'N')
	{
		me.SetError('Debe indicar un criterio de Clasificación de Fichadas');
		return false;
	}
	return true;	
}
